import{tokenisePath}from"./treeUtil";const Parent=Symbol("parent");const BaseSymbol=Symbol("base");class KVTree{register(path,value){const newPath=tokenisePath(path);const base=newPath.shift();if(newPath.length===0){this[base]=value;return}if(!(base in this)){this[base]=new KVTree(base,this)}this[base].register(newPath.join("/"),value)}get(path){const newPath=tokenisePath(path);const base=newPath.shift();const val=this[base];return newPath.length>0?val?.get?.(newPath):val}get path(){if(!this[Parent])return"";return[this[Parent].path,this[BaseSymbol]].join("/")}toJSON(){return Object.entries(this).reduce((cur,[key,obj])=>{return{...cur,[key]:repr(obj)}},{})}constructor(base="/",parent=null){this[BaseSymbol]=base;this[Parent]=parent}}export{KVTree as default};function repr(obj){if(obj instanceof KVTree)return obj.toJSON();if(obj instanceof Buffer)return obj.toString("hex");if(typeof obj==="bigint")return obj.toString();return obj}